const $=(s,r=document)=>r.querySelector(s)||(s==='#theme'?{}:null), money=v=>(v/100).toLocaleString('pt-BR',{style:'currency',currency:'BRL'}), esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const params=new URLSearchParams(location.search), page=document.body.dataset.page||'home';
const VIEWED_PRODUCTS_KEY='shoplab:viewed-products';
function viewedProducts(){try{const value=JSON.parse(localStorage.getItem(VIEWED_PRODUCTS_KEY)||'[]');return Array.isArray(value)?value:[]}catch{return[]}}
function rememberViewedProduct(product){if(!product?.slug)return;try{const recent=viewedProducts().filter(item=>item.slug!==product.slug);recent.unshift({slug:product.slug,viewedAt:Date.now()});localStorage.setItem(VIEWED_PRODUCTS_KEY,JSON.stringify(recent.slice(0,12)))}catch{}}
