function warmHeaderMedia(config){const wide=matchMedia('(min-width:761px)').matches,urls=[config?.theme?.logoUrl,config?.theme?.headerMediaUrl,wide?(config?.headerSpotlights||[])[0]?.mediaUrl:null].filter(Boolean),loaded=[...document.head.querySelectorAll('link[data-header-preload]')].map(link=>link.href);for(const url of new Set(urls)){const absolute=new URL(url,location.href).href;if(loaded.includes(absolute))continue;const link=document.createElement('link');link.rel='preload';link.as='image';link.href=absolute;link.dataset.headerPreload='true';document.head.append(link);loaded.push(absolute)}}
function homeBanner(){const banners=siteConfig.banners||[];if(!banners.length)return'';const slides=banners.map((b,index)=>`<a class="home-banner-slide ${index===0?'is-active':''}" href="${esc(b.linkUrl)}" aria-label="${esc(b.buttonText||b.title||b.name)}" aria-hidden="${index===0?'false':'true'}" tabindex="${index===0?'0':'-1'}" data-banner-slide="${index}"><picture><source media="(max-width:600px)" srcset="${esc(b.mobileImageUrl||b.desktopImageUrl)}"><img src="${esc(b.desktopImageUrl)}" alt="${esc(b.altText||b.title||b.name)}" ${index===0?'fetchpriority="high"':'loading="lazy"'}></picture><span class="home-banner-shade"></span><span class="home-banner-copy"><small>${esc(b.eyebrow)}</small><strong>${esc(b.title)}</strong><span>${esc(b.message)}</span><b>${esc(b.buttonText||'Ver oferta')} →</b></span></a>`).join('');const controls=banners.length>1?`<button class="home-banner-arrow previous" type="button" data-banner-previous aria-label="Banner anterior">‹</button><button class="home-banner-arrow next" type="button" data-banner-next aria-label="Próximo banner">›</button><div class="home-banner-dots" role="tablist" aria-label="Escolher banner">${banners.map((b,index)=>`<button type="button" role="tab" aria-label="Mostrar banner ${index+1}: ${esc(b.name||b.title)}" aria-selected="${index===0?'true':'false'}" class="${index===0?'is-active':''}" data-banner-dot="${index}"></button>`).join('')}</div><span class="home-banner-progress" aria-hidden="true"><i></i></span>`:'';return `<section class="home-banner-section"><div class="container"><div class="home-banner" data-banner-carousel data-interval="6000">${slides}${controls}</div></div></section>`}

function bindHomeBanner(){const carousel=document.querySelector('[data-banner-carousel]');if(!carousel)return;const slides=[...carousel.querySelectorAll('[data-banner-slide]')],dots=[...carousel.querySelectorAll('[data-banner-dot]')];if(slides.length<2)return;let current=0,timer=null,startX=null;const reduced=matchMedia('(prefers-reduced-motion: reduce)').matches;const show=(index,userInitiated=false)=>{current=(index+slides.length)%slides.length;slides.forEach((slide,i)=>{const active=i===current;slide.classList.toggle('is-active',active);slide.setAttribute('aria-hidden',String(!active));slide.tabIndex=active?0:-1});dots.forEach((dot,i)=>{const active=i===current;dot.classList.toggle('is-active',active);dot.setAttribute('aria-selected',String(active))});carousel.style.setProperty('--banner-progress',userInitiated?'0s':`${Number(carousel.dataset.interval)||6000}ms`)};const stop=()=>{clearInterval(timer);timer=null};const play=()=>{stop();if(reduced||document.hidden)return;timer=setInterval(()=>show(current+1),Number(carousel.dataset.interval)||6000)};const go=index=>{show(index,true);play()};carousel.querySelector('[data-banner-previous]')?.addEventListener('click',()=>go(current-1));carousel.querySelector('[data-banner-next]')?.addEventListener('click',()=>go(current+1));dots.forEach(dot=>dot.addEventListener('click',()=>go(Number(dot.dataset.bannerDot))));carousel.addEventListener('mouseenter',stop);carousel.addEventListener('mouseleave',play);carousel.addEventListener('focusin',stop);carousel.addEventListener('focusout',event=>{if(!carousel.contains(event.relatedTarget))play()});carousel.addEventListener('pointerdown',event=>{startX=event.clientX});carousel.addEventListener('pointerup',event=>{if(startX==null)return;const distance=event.clientX-startX;startX=null;if(Math.abs(distance)>45)go(current+(distance<0?1:-1))});document.addEventListener('visibilitychange',()=>document.hidden?stop():play());show(0);play()}
function applySiteTheme(theme){const root=document.documentElement;if(!theme){delete root.dataset.seasonalTheme;return}const headerEnd=theme.headerBackgroundEnd||theme.headerBackground,headerBackground=Number(theme.headerGradientEnabled)?`linear-gradient(${Number(theme.headerGradientAngle)||0}deg,${theme.headerBackground},${headerEnd})`:theme.headerBackground,mediaUrl=String(theme.headerMediaUrl||'').replace(/["\\]/g,''),mediaSize=theme.headerMediaSize==='custom'?`${Math.min(400,Math.max(10,Number(theme.headerMediaScale)||100))}% auto`:theme.headerMediaSize||'cover';root.style.setProperty('--season-header-bg',theme.headerBackground);root.style.setProperty('--season-header-background',headerBackground);root.style.setProperty('--season-header-text',theme.headerTextColor);root.style.setProperty('--season-header-image',mediaUrl?`url("${mediaUrl}")`:'none');root.style.setProperty('--season-header-image-opacity',String(Math.min(1,Math.max(0,Number(theme.headerMediaOpacity)||0))));root.style.setProperty('--season-header-image-position',theme.headerMediaPosition||'center');root.style.setProperty('--season-header-image-size',mediaSize);root.style.setProperty('--season-header-image-repeat',Number(theme.headerMediaRepeat)?'repeat':'no-repeat');root.style.setProperty('--accent',theme.accentColor);root.style.setProperty('--accent-hover',`color-mix(in srgb,${theme.accentColor} 82%,#000)`);root.style.setProperty('--text',theme.pageTextColor);root.style.setProperty('--muted',theme.mutedTextColor);root.style.setProperty('--bg',`color-mix(in srgb,${theme.accentColor} 4%,#fff)`);root.style.setProperty('--surface','#fff');root.style.setProperty('--surface-soft',`color-mix(in srgb,${theme.accentColor} 8%,#fff)`);root.style.setProperty('--surface-elevated',`color-mix(in srgb,${theme.accentColor} 5%,#fff)`);root.style.setProperty('--border',`color-mix(in srgb,${theme.accentColor} 20%,#d8d8d8)`);root.style.setProperty('--shadow',`0 8px 24px color-mix(in srgb,${theme.accentColor} 14%,transparent)`);root.dataset.seasonalTheme=theme.id;let meta=document.querySelector('meta[name="theme-color"]');if(!meta){meta=document.createElement('meta');meta.name='theme-color';document.head.append(meta)}meta.content=theme.headerBackground}
function headerHighlight(){const spotlights=(siteConfig.headerSpotlights||[]).filter(item=>item.mediaUrl),wide=matchMedia('(min-width:761px)').matches;if(spotlights.length){const slides=spotlights.map((spotlight,index)=>{const href=spotlight.linkUrl||'promocoes.html',alt=spotlight.altText||spotlight.name||'Destaque SHOPLAB',source=esc(spotlight.mediaUrl);return `<a class="header-highlight-slide ${index===0?'is-active':''}" href="${esc(href)}" title="${esc(alt)}" aria-hidden="${index===0?'false':'true'}" tabindex="${index===0?'0':'-1'}" data-header-spotlight-slide><img ${wide?`src="${source}" `:''}data-src="${source}" alt="${esc(alt)}" width="560" height="92" decoding="async" ${index?'loading="lazy"':'fetchpriority="high"'}></a>`}).join('');return `<div class="header-highlight has-media header-highlight-carousel" data-header-spotlight-carousel data-interval="5000">${slides}${spotlights.length>1?`<span class="header-highlight-counter" aria-hidden="true">1/${spotlights.length}</span>`:''}</div>`}const promotion=(siteConfig.headerPromotions||[])[0];let label='OFERTAS VERIFICADAS',detail='CONFIRA AGORA',href='promocoes.html';if(promotion){const value=Number(promotion.discountValue)||0;label=promotion.name;detail=promotion.discountType==='percentage'&&value?`ATÉ ${value}% OFF`:promotion.discountType==='fixed'&&value?`${money(Math.round(value*100))} OFF`:promotion.couponCode?`CUPOM ${promotion.couponCode}`:'VER PROMOÇÃO';href=`promocoes.html#${encodeURIComponent(promotion.slug)}`}return `<a class="header-highlight" href="${href}" title="${esc(label)}"><span>${esc(label)}</span><strong>${esc(detail)}</strong><i>→</i></a>`}
function bindHeaderSpotlights(){const carousel=document.querySelector('[data-header-spotlight-carousel]');if(!carousel)return;const slides=[...carousel.querySelectorAll('[data-header-spotlight-slide]')],counter=carousel.querySelector('.header-highlight-counter'),mediaQuery=matchMedia('(min-width:761px)'),syncMedia=()=>carousel.querySelectorAll('img[data-src]').forEach(img=>{if(mediaQuery.matches&&!img.getAttribute('src'))img.src=img.dataset.src;else if(!mediaQuery.matches)img.removeAttribute('src')});syncMedia();mediaQuery.addEventListener?.('change',syncMedia);slides.forEach(slide=>slide.addEventListener('click',event=>{if(event.button!==0||event.metaKey||event.ctrlKey||event.shiftKey||event.altKey)return;event.preventDefault();location.assign(slide.href)}));if(slides.length<2)return;let current=0,timer;const reduced=matchMedia('(prefers-reduced-motion: reduce)').matches,show=index=>{current=(index+slides.length)%slides.length;slides.forEach((slide,i)=>{const active=i===current;slide.classList.toggle('is-active',active);slide.setAttribute('aria-hidden',String(!active));slide.tabIndex=active?0:-1});if(counter)counter.textContent=`${current+1}/${slides.length}`},stop=()=>clearInterval(timer),play=()=>{stop();if(!reduced&&!document.hidden&&mediaQuery.matches)timer=setInterval(()=>show(current+1),Number(carousel.dataset.interval)||5000)};carousel.addEventListener('mouseenter',stop);carousel.addEventListener('mouseleave',play);carousel.addEventListener('focusin',stop);carousel.addEventListener('focusout',event=>{if(!carousel.contains(event.relatedTarget))play()});mediaQuery.addEventListener?.('change',()=>mediaQuery.matches?play():stop());document.addEventListener('visibilitychange',()=>document.hidden?stop():play());play()}
function header(){const theme=siteConfig.theme||{},logo=theme.logoText,logoContent=theme.logoUrl?`<span class="brand-images"><img class="brand-image brand-image-main" src="${esc(theme.logoUrl)}" alt="${esc(logo||'SHOPLAB')}" width="420" height="72" decoding="async" fetchpriority="high">${theme.logoHoverUrl?`<img class="brand-image brand-image-hover" src="${esc(theme.logoHoverUrl)}" alt="" width="420" height="72" decoding="async">`:''}</span>`:`<span class="brand-images default-site-logo"><img class="brand-image brand-image-main" src="assets/img/shoplab-wordmark.png" alt="SHOPLAB" width="420" height="72" decoding="async" fetchpriority="high"></span>`,logged=Boolean(authSession()),cartCount=Object.values(localLibrary().cart).reduce((sum,value)=>sum+Number(value||0),0),cart=`<a class="nav-cart" href="${logged?'conta.html#cart-list':'entrar.html?next=conta.html%23cart-list'}" aria-label="Carrinho com ${cartCount} itens"><img src="assets/icons/cart.svg" alt=""><span>Carrinho</span><b data-cart-count ${cartCount?'':'hidden'}>${cartCount}</b></a>`,account=logged?`<details class="account-menu"><summary><span class="account-avatar" data-account-avatar><img src="assets/icons/user.svg" alt=""></span><span data-account-name>Minha conta</span><i class="account-chevron" aria-hidden="true"></i></summary><div class="account-dropdown"><header><span class="account-avatar large" data-account-avatar><img src="assets/icons/user.svg" alt=""></span><div><strong data-account-name>Minha conta</strong><small data-account-email></small></div></header><a href="conta.html">Meu perfil</a><a href="conta.html#cart-list">Carrinho</a><a href="conta.html#favorites-list">Produtos curtidos</a><a href="conta.html#ratings-list">Minhas avaliações</a><a href="conta.html#history-list">Histórico</a><button type="button" data-account-signout>Sair</button></div></details>`:`<a class="nav-login" href="entrar.html"><img src="assets/icons/user.svg" alt=""><span>Entrar</span></a>`,navLinks=`<a href="produtos.html">Todos os produtos</a><a href="categoria.html?slug=livros">Livros</a><a href="categoria.html?slug=tecnologia">Tecnologia</a><a href="promocoes.html">Ofertas</a><a href="novidades.html">Novidades</a><span class="nav-account-actions">${cart}${account}</span>`;return `<header class="header"><div class="container header-row"><a class="logo header-brand" href="index.html" aria-label="SHOPLAB início">${logoContent}</a><form class="search" action="busca.html"><label class="sr-only" for="q">Pesquisar</label><input id="q" name="q" value="${esc(params.get('q')||'')}" placeholder="O que você está procurando?" autocomplete="off"><button type="submit" aria-label="Pesquisar"><img src="assets/icons/search.svg" alt=""></button></form>${headerHighlight()}</div><nav class="subnav"><div class="container"><div class="desktop-nav-links">${navLinks}</div><details class="mobile-nav"><summary>Explorar o site</summary><div>${navLinks}</div></details></div></nav></header>`}
async function bindAccountHeader(){const updateCount=event=>{const count=Object.values(localLibrary().cart).reduce((sum,value)=>sum+Number(value||0),0);document.querySelectorAll('[data-cart-count]').forEach(badge=>{badge.textContent=count;badge.hidden=!count});if(event?.detail?.type==='ratings')bindRatingSummaries().catch(()=>null)};updateCount();window.addEventListener('shoplab:library-change',updateCount);const menu=document.querySelector('.account-menu');if(!menu)return;const positionMenu=()=>{if(!menu.open)return;const rect=menu.querySelector('summary').getBoundingClientRect();menu.style.setProperty('--account-menu-top',`${Math.round(rect.bottom+8)}px`);menu.style.setProperty('--account-menu-right',`${Math.max(10,Math.round(innerWidth-rect.right))}px`)};menu.addEventListener('toggle',()=>{if(menu.open)requestAnimationFrame(positionMenu)});addEventListener('resize',positionMenu,{passive:true});addEventListener('scroll',positionMenu,{passive:true});const user=await currentUser();if(!user)return;const name=String(user.user_metadata?.display_name||user.user_metadata?.full_name||user.email?.split('@')[0]||'Minha conta'),avatar=String(user.user_metadata?.avatar_url||user.user_metadata?.picture||'');document.querySelectorAll('[data-account-name]').forEach(item=>item.textContent=name);document.querySelectorAll('[data-account-email]').forEach(item=>item.textContent=user.email||'');document.querySelectorAll('[data-account-avatar]').forEach(item=>{item.innerHTML=avatar?`<img src="${esc(avatar)}" alt="Foto de ${esc(name)}" referrerpolicy="no-referrer">`:`<b>${esc(name.trim().split(/\s+/).slice(0,2).map(part=>part[0]).join('').toUpperCase())}</b>`});document.querySelector('[data-account-signout]')?.addEventListener('click',async()=>{await signOut();location.replace('index.html')});document.addEventListener('click',event=>{if(menu.open&&!menu.contains(event.target))menu.removeAttribute('open')})}
function paintRatingSummary(target,average,total){target.hidden=false;target.dataset.ratingAverage=String(Number(average)||0);target.dataset.ratingTotal=String(Number(total)||0);target.innerHTML=`<span aria-hidden="true">★</span><strong>${Number(average||0).toFixed(1)}</strong><small>${Number(total)||0} ${(Number(total)||0)===1?'avaliação':'avaliações'}</small>`}
function updateRatingOptimistically({slug,rating,oldValue}){document.querySelectorAll(`[data-rating-summary="${CSS.escape(slug)}"]`).forEach(target=>{const total=Number(target.dataset.ratingTotal)||0,average=Number(target.dataset.ratingAverage)||0,previous=Number(oldValue)||0,next=Number(rating)||0,newTotal=previous?total:total+1,newAverage=newTotal?((average*total)-previous+next)/newTotal:next;paintRatingSummary(target,newAverage,newTotal)})}
async function bindRatingSummaries(){const targets=[...document.querySelectorAll('[data-rating-summary]')],slugs=[...new Set(targets.map(item=>item.dataset.ratingSummary).filter(Boolean))];if(!slugs.length)return;const response=await fetch(`${SHOPLAB_CONFIG.API_BASE_URL}/api/v1/ratings?slugs=${encodeURIComponent(slugs.join(','))}&t=${Date.now()}`,{cache:'no-store'}),payload=await response.json();if(!response.ok||!payload.success)return;const summaries=new Map(payload.data.map(item=>[item.slug,item]));targets.forEach(target=>{const value=summaries.get(target.dataset.ratingSummary)||{average:0,total:0};paintRatingSummary(target,value.average,value.total)})}
window.addEventListener('shoplab:library-change',event=>{if(event.detail?.type==='rating-preview')updateRatingOptimistically(event.detail)});
function storeStrip(){const stores=siteConfig.stores||[];if(!stores.length)return'';const repeated=Array.from({length:Math.max(2,Math.ceil(10/stores.length))},()=>stores).flat(),cards=repeated.map(store=>`<a class="store-marquee-card" href="produtos.html?store=${encodeURIComponent(store.slug)}" aria-label="Ver produtos da loja ${esc(store.name)}">${store.logoUrl?`<img src="${esc(store.logoUrl)}" alt="" loading="lazy">`:`<span>${esc(store.name).slice(0,1)}</span>`}<strong>${esc(store.name)}</strong><small>${Number(store.productCount)||0} ${(Number(store.productCount)||0)===1?'produto':'produtos'}</small><b>Explorar →</b></a>`).join('');return `<div class="commerce-marquee-row"><div class="container commerce-row-head"><div><span>LOJAS</span><h3>Onde encontrar as melhores ofertas</h3></div><a href="produtos.html">Ver catálogo →</a></div><div class="store-marquee" tabindex="0"><div class="store-marquee-track" style="--store-marquee-duration:${Math.max(28,repeated.length*3.5)}s"><div class="store-marquee-group">${cards}</div><div class="store-marquee-group" aria-hidden="true">${cards}</div></div></div></div>`}
function brandStrip(){const brands=siteConfig.brands||[];if(!brands.length)return'';const repeated=Array.from({length:Math.max(2,Math.ceil(10/brands.length))},()=>brands).flat(),cards=repeated.map(brand=>`<a class="store-marquee-card brand-marquee-card" href="marca.html?slug=${encodeURIComponent(brand.slug)}" aria-label="Ver produtos da marca ${esc(brand.name)}">${brand.logoUrl?`<img src="${esc(brand.logoUrl)}" alt="" loading="lazy">`:`<span>${esc(brand.name).slice(0,1)}</span>`}<strong>${esc(brand.name)}</strong><small>${Number(brand.productCount)||0} ${(Number(brand.productCount)||0)===1?'produto':'produtos'}</small><b>Explorar →</b></a>`).join('');return `<div class="commerce-marquee-row"><div class="container commerce-row-head"><div><span>MARCAS</span><h3>Encontre pelo nome que você confia</h3></div><a href="produtos.html">Ver catálogo →</a></div><div class="store-marquee brand-marquee" tabindex="0"><div class="store-marquee-track" style="--store-marquee-duration:${Math.max(28,repeated.length*3.5)}s"><div class="store-marquee-group">${cards}</div><div class="store-marquee-group" aria-hidden="true">${cards}</div></div></div></div>`}
function commerceShowcase(){const partners=[...(siteConfig.stores||[]).map(item=>({...item,type:'store'})),...(siteConfig.brands||[]).map(item=>({...item,type:'brand'}))].filter((item,index,list)=>list.findIndex(other=>String(other.name).toLowerCase()===String(item.name).toLowerCase())===index).slice(0,7);if(!partners.length)return'';const logos=partners.map(item=>{const href=item.type==='brand'?`marca.html?slug=${encodeURIComponent(item.slug)}`:`produtos.html?store=${encodeURIComponent(item.slug)}`;return `<a class="partner-logo" href="${href}" aria-label="Ver produtos de ${esc(item.name)}">${item.logoUrl?`<img src="${esc(item.logoUrl)}" alt="${esc(item.name)}" loading="lazy">`:`<strong>${esc(item.name)}</strong>`}</a>`}).join('');return `<section class="commerce-showcase partner-strip-section" aria-label="Parceiros confiáveis"><div class="container partner-strip"><div class="partner-trust"><span aria-hidden="true">✓</span><strong>Ofertas de parceiros confiáveis</strong></div><div class="partner-logos">${logos}</div><a class="partner-all" href="produtos.html">Ver todos os parceiros →</a></div></section>`}
function mobileHomeCategories(){return `<nav class="mobile-home-categories" aria-label="Categorias em destaque"><a class="active" href="produtos.html">Todos</a><a href="promocoes.html">Ofertas</a><a href="categoria.html?slug=tecnologia">Tecnologia</a><a href="categoria.html?slug=livros">Livros</a><a href="produtos.html">Mais</a></nav>`}
function footer(){const theme=siteConfig.theme||{},footerLogo=theme.logoUrl||'assets/img/shoplab-wordmark.png';return `${page==='home'?commerceShowcase():''}<footer class="footer"><div class="container"><div class="footer-grid"><div><a class="footer-logo" href="index.html" aria-label="SHOPLAB início"><img src="${esc(footerLogo)}" alt="SHOPLAB"></a><p class="muted">Pesquisa, comparação e recomendações para escolhas mais inteligentes.</p></div><div><h4>Descobrir</h4><a href="produtos.html">Produtos</a><a href="promocoes.html">Ofertas</a><a href="novidades.html">Novidades</a></div><div><h4>SHOPLAB</h4><a href="sobre.html">Sobre</a><a href="contato.html">Contato</a><a href="politica-de-afiliados.html">Como ganhamos dinheiro</a></div><div><h4>Ajuda e segurança</h4><a href="politica-de-privacidade.html">Privacidade</a><a href="termos-de-uso.html">Termos de uso</a></div></div><div class="footer-bottom">© 2026 SHOPLAB. Os preços podem mudar. Confira as condições na loja parceira.</div></div></footer>`}
function card(p){const detailsUrl=`produto.html?slug=${encodeURIComponent(p.slug)}`,symbol=p.icon||({'Livros e e-books':'▤','Tecnologia':'⌘','Áudio':'♫','Produtividade':'✓'}[p.category]||'⌬'),compareIcon='<img src="assets/icons/compare.svg" alt="">',badge=Number(p.discount)>0?`${Number(p.discount)}% OFF`:p.tag||'Analisado';return `<article class="product-card" data-card-url="${esc(detailsUrl)}" tabindex="0" aria-label="Ver ${esc(p.name)}"><a class="product-media" href="${detailsUrl}" tabindex="-1"><span class="badge">${esc(badge)}</span><span class="product-symbol" role="img" aria-label="Imagem ilustrativa">${esc(symbol)}</span></a><button class="card-compare icon-compare compare-product" type="button" data-compare-product="${esc(p.slug)}" data-compare-name="${esc(p.name)}" data-compare-category="${esc(p.category||'Sem categoria')}" aria-label="Selecionar ${esc(p.name)} para comparar" aria-pressed="false">${compareIcon}</button><div class="product-body"><span class="meta">${esc(p.category)}${p.brand?` · ${esc(p.brand)}`:''}</span><h3>${esc(p.name)}</h3><span class="public-rating" data-rating-summary="${esc(p.slug)}"><span aria-hidden="true">★</span><strong>0.0</strong><small>0 avaliações</small></span><div class="price">${money(p.price)} ${p.oldPrice?`<span class="old">${money(p.oldPrice)}</span>`:''}</div></div></article>`}
function section(title,sub,items,id=''){return `<section class="section" ${id?`id="${id}"`:''}><div class="container"><div class="section-head"><div><span class="eyebrow">Curadoria SHOPLAB</span><h2>${title}</h2></div><p>${sub}</p></div><div class="products">${items.map(card).join('')}</div></div></section>`}
