const defaultInstitutional=institutional;
institutional=()=>{
  const pages={
    about:{title:'Sobre a SHOPLAB',intro:'A SHOPLAB organiza produtos, preços, promoções e análises para ajudar você a comparar opções com mais clareza antes de visitar a loja.',sections:[['O que fazemos','Reunimos informações importantes em um só lugar: preço atual, preço anterior, descontos, campanhas, imagens, descrição, categoria e links das lojas parceiras.'],['Como funciona a curadoria','Os produtos podem receber uma nota editorial SHOPLAB baseada em critérios de qualidade, utilidade, custo-benefício e adequação ao público. Essa nota é da nossa análise e não representa avaliações de consumidores.'],['Preços e promoções','Mostramos os valores cadastrados e destacamos promoções ativas com porcentagem de desconto e prazo de encerramento. Como preços e estoque pertencem às lojas, recomendamos confirmar tudo antes de concluir a compra.'],['Transparência com afiliados','Alguns botões direcionam para links afiliados. A SHOPLAB poderá receber uma comissão quando uma compra qualificada acontecer, sem custo adicional para o visitante.'],['Nosso compromisso','Buscamos apresentar informações diretas, corrigir dados desatualizados e deixar clara a diferença entre análise editorial, promoção e informação fornecida por terceiros.'],['Fale conosco','Para sugerir produtos, informar um preço incorreto, solicitar uma correção ou tratar de parceria, escreva para bidjorysamuel@gmail.com.']]},
    contact:{title:'Fale com a SHOPLAB',intro:'Envie dúvidas, correções, sugestões de produtos ou propostas de parceria. Sua mensagem será direcionada para bidjorysamuel@gmail.com.',contact:true,sections:[]},
    privacy:{title:'Política de privacidade',intro:'Esta política explica quais dados a SHOPLAB trata, por qual motivo e quais escolhas você possui.',sections:[['1. Dados tratados','Podemos receber dados técnicos essenciais, como endereço IP, navegador, dispositivo, páginas acessadas, horário, origem da visita e eventos de uso. Quando recursos de conta forem ativados, também poderemos tratar nome, e-mail, itens salvos e preferências.'],['2. Finalidades','Usamos os dados para entregar o site, proteger a plataforma, manter sessões, medir desempenho, melhorar busca e recomendações, evitar fraude e entender cliques em ofertas. Não vendemos dados pessoais.'],['3. Cookies e armazenamento','Cookies essenciais podem manter sessões administrativas e preferências. Recursos de medição ou personalização não essenciais devem respeitar as escolhas aplicáveis do visitante.'],['4. Links e parceiros','Ao abrir uma oferta, você poderá ser direcionado a uma loja parceira. A loja possui política própria e pode tratar dados de acordo com seus termos. A SHOPLAB pode receber comissão por compras qualificadas.'],['5. Compartilhamento e infraestrutura','Dados podem ser processados por fornecedores de hospedagem, segurança, armazenamento e análise estritamente necessários à operação. Exigimos uso compatível com a finalidade contratada.'],['6. Conservação e segurança','Mantemos dados somente pelo período necessário às finalidades descritas, obrigações legais e prevenção de abuso. Aplicamos controles técnicos e administrativos, embora nenhum sistema seja totalmente imune a incidentes.'],['7. Seus direitos','Você pode solicitar confirmação de tratamento, acesso, correção, exclusão, informação sobre compartilhamento e revisão das permissões aplicáveis, observadas as exceções legais.'],['8. Contato e atualizações','Solicitações de privacidade podem ser enviadas pela página de contato. Esta política poderá ser atualizada para refletir mudanças legais ou operacionais; a versão publicada nesta página será a vigente.']]},
    terms:{title:'Termos de uso',intro:'Ao utilizar a SHOPLAB, você concorda com as condições abaixo. Leia especialmente as regras sobre preços, conteúdo editorial e links afiliados.',sections:[['1. Natureza do serviço','A SHOPLAB pesquisa, organiza e compara informações de produtos e ofertas. Não somos a loja vendedora, transportadora, fabricante nem processadora do pagamento.'],['2. Preços e disponibilidade','Preços, estoque, frete, parcelamento, cupons e condições podem mudar sem aviso. O valor definitivo é sempre o exibido pela loja parceira no momento da compra. Contadores indicam o prazo cadastrado da campanha, mas não garantem estoque.'],['3. Links afiliados','Alguns links identificam a SHOPLAB como afiliada. Podemos receber comissão sem custo adicional para o visitante. Isso não transfere à SHOPLAB responsabilidade pela venda nem altera os critérios editoriais declarados.'],['4. Avaliações e conteúdo','Notas SHOPLAB são avaliações editoriais, não avaliações de consumidores. Conteúdo, imagens, especificações e comparações têm finalidade informativa e podem conter erros ou ficar desatualizados.'],['5. Uso permitido','Você pode navegar e compartilhar links para uso pessoal. É proibido interferir na segurança, automatizar coleta abusiva, tentar acessar áreas restritas, copiar substancialmente o banco de dados ou usar o serviço para fraude.'],['6. Serviços de terceiros','Compras, pagamentos, garantias, devoluções, suporte e tratamento de dados na loja seguem os termos do respectivo parceiro. Verifique-os antes de concluir uma transação.'],['7. Limitação de responsabilidade','Na extensão permitida pela lei, a SHOPLAB não responde por decisões tomadas exclusivamente com base no conteúdo, indisponibilidade temporária, alterações de terceiros ou prejuízos decorrentes da relação entre consumidor e loja. Direitos obrigatórios do consumidor permanecem preservados.'],['8. Alterações e contato','Podemos modificar funcionalidades e estes termos. A continuidade de uso após a publicação indica ciência da versão vigente. Dúvidas e comunicações podem ser enviadas pela página de contato.']]}
  },content=pages[page];
  if(!content)return defaultInstitutional();
  if(content.contact)return `<main id="conteudo"><div class="container page-hero contact-page"><span class="eyebrow">CONTATO</span><h1 class="page-title">${content.title}</h1><p class="legal-intro">${content.intro}</p><div class="contact-grid"><form id="contact-form" class="form-grid contact-card"><div class="form-field"><label for="contact-name">Seu nome</label><input id="contact-name" required maxlength="100" autocomplete="name"></div><div class="form-field"><label for="contact-email">Seu e-mail</label><input id="contact-email" type="email" required maxlength="160" autocomplete="email"></div><div class="form-field full"><label for="contact-subject">Assunto</label><select id="contact-subject"><option>Dúvida</option><option>Correção de produto ou preço</option><option>Sugestão de produto</option><option>Parceria comercial</option><option>Privacidade</option><option>Outro assunto</option></select></div><div class="form-field full"><label for="contact-message">Mensagem</label><textarea id="contact-message" required rows="7" maxlength="4000" placeholder="Conte como podemos ajudar"></textarea></div><button class="btn primary" type="submit">Enviar por e-mail</button></form><aside class="contact-direct"><span class="eyebrow">E-MAIL DIRETO</span><h2>Prefere escrever diretamente?</h2><a class="contact-email" href="mailto:bidjorysamuel@gmail.com">bidjorysamuel@gmail.com</a><p class="muted">Ao enviar o formulário, abriremos seu aplicativo de e-mail com a mensagem preenchida. Você poderá revisar antes de enviar.</p></aside></div></div></main>`;
  return `<main id="conteudo"><article class="container legal-page"><span class="eyebrow">TRANSPARÊNCIA</span><h1 class="page-title">${content.title}</h1><p class="legal-intro">${content.intro}</p><p class="legal-updated">Última atualização: 15 de julho de 2026.</p>${content.sections.map(([title,text])=>`<section><h2>${title}</h2><p>${text}</p></section>`).join('')}</article></main>`;
};

init().then(async()=>{startPresence();bindHomeBanner();bindHomeBannerSwipeGuard();await syncAccountLibrary().catch(()=>null);await bindLibraryUI();bindProductImpressions();await Promise.all([bindAccountHeader(),bindRatingSummaries().catch(()=>null)])});

function bindProductImpressions(){
  if(!authSession()||!('IntersectionObserver'in window))return;
  const impressionKey='shoplab:impressions-session',stored=(()=>{try{return JSON.parse(sessionStorage.getItem(impressionKey)||'[]')}catch{return[]}})();
  const seen=new Set(Array.isArray(stored)?stored:[]),queue=[];
  let timer;
  const flush=()=>{timer=undefined;if(!queue.length)return;trackEvent({events:queue.splice(0,20)}).catch(()=>{});if(queue.length)timer=setTimeout(flush,800)};
  const observer=new IntersectionObserver(entries=>entries.forEach(entry=>{
    if(!entry.isIntersecting||entry.intersectionRatio<.5)return;
    const card=entry.target,slug=new URL(card.dataset.cardUrl||'',location.href).searchParams.get('slug');
    observer.unobserve(card);if(!slug||seen.has(slug)||seen.size>=60)return;seen.add(slug);sessionStorage.setItem(impressionKey,JSON.stringify([...seen]));queue.push({type:'product_impression',slug,metadata:{page}});if(queue.length>=12)flush();else timer??=setTimeout(flush,800);
  }),{threshold:.5});
  document.querySelectorAll('.product-card').forEach(card=>observer.observe(card));
}

function bindHomeBannerSwipeGuard(){const carousel=document.querySelector('[data-banner-carousel]');if(!carousel)return;let startX=0,moved=false;carousel.style.touchAction='pan-y';carousel.addEventListener('pointerdown',event=>{startX=event.clientX;moved=false},{passive:true});carousel.addEventListener('pointermove',event=>{if(Math.abs(event.clientX-startX)>18)moved=true},{passive:true});carousel.addEventListener('click',event=>{if(moved&&event.target.closest('[data-banner-slide]')){event.preventDefault();event.stopPropagation();moved=false}},true)}

const removeDemoCopy=()=>{const walker=document.createTreeWalker(document.body,NodeFilter.SHOW_TEXT);let node;while((node=walker.nextNode())){if(node.nodeValue.includes('Link afiliado demonstrativo.'))node.nodeValue=node.nodeValue.replace('Link afiliado demonstrativo.','Confira o preço e as condições na loja parceira.');if(node.nodeValue.includes('dados demonstrativos atualizados.'))node.nodeValue=node.nodeValue.replace('dados demonstrativos atualizados.','resultados disponíveis.')}};
removeDemoCopy();
new MutationObserver(removeDemoCopy).observe(document.body,{childList:true,subtree:true});

document.addEventListener('submit',event=>{if(event.target.id!=='contact-form')return;event.preventDefault();const name=document.querySelector('#contact-name').value.trim(),email=document.querySelector('#contact-email').value.trim(),subject=document.querySelector('#contact-subject').value,message=document.querySelector('#contact-message').value.trim();const body=`Nome: ${name}\nE-mail para resposta: ${email}\n\n${message}`;location.href=`mailto:bidjorysamuel@gmail.com?subject=${encodeURIComponent(`[SHOPLAB] ${subject}`)}&body=${encodeURIComponent(body)}`});

function updateCardCountdowns(){document.querySelectorAll('.card-countdown[data-ends]').forEach(counter=>{const remaining=Math.max(0,new Date(counter.dataset.ends).getTime()-Date.now()),seconds=Math.floor(remaining/1000)%60,minutes=Math.floor(remaining/60000)%60,hours=Math.floor(remaining/3600000)%24,days=Math.floor(remaining/86400000);counter.textContent=remaining?`${days}d ${String(hours).padStart(2,'0')}:${String(minutes).padStart(2,'0')}:${String(seconds).padStart(2,'0')}`:'Encerrada'})}
updateCardCountdowns();
setInterval(updateCardCountdowns,1000);

if(page==='product'){
  const slug=params.get('slug');
  const viewKey=slug?`shoplab-viewed:${slug}`:'';
  if(slug&&!sessionStorage.getItem(viewKey)){
    sessionStorage.setItem(viewKey,'1');
    trackEvent({type:'product_view',slug,metadata:{source:document.referrer||'direct'}}).catch(()=>{});
  }
  getProductBySlug(slug).then(product=>{
    if(!product)return;
    const applyLogos=()=>{
      const storeLine=document.querySelector('.offer p');
      if(storeLine&&product.storeLogoUrl&&!storeLine.querySelector('img')){
        storeLine.classList.add('entity-with-logo');
        storeLine.insertAdjacentHTML('afterbegin',`<img class="entity-logo store-logo" src="${esc(product.storeLogoUrl)}" alt="Logo ${esc(product.store||'da loja')}" loading="lazy">`);
      }
      const brandValue=document.querySelector('.specs .spec:first-child strong');
      if(brandValue&&product.brandLogoUrl&&!brandValue.parentElement.querySelector('img')){
        brandValue.parentElement.classList.add('entity-spec');
        brandValue.insertAdjacentHTML('beforebegin',`<img class="entity-logo brand-logo" src="${esc(product.brandLogoUrl)}" alt="Logo ${esc(product.brand||'da marca')}" loading="lazy">`);
      }
    };
    applyLogos();
    const observer=new MutationObserver(()=>{applyLogos();if(document.querySelector('.offer p'))observer.disconnect()});
    observer.observe(document.body,{childList:true,subtree:true});
  }).catch(()=>{});
}

if(page==='search'){
  document.addEventListener('click',event=>{
    const link=event.target.closest('.product-card a[href*="produto.html?slug="]');
    if(!link)return;
    const slug=new URL(link.href,location.href).searchParams.get('slug');
    if(slug)trackEvent({type:'search_result_click',slug,query:params.get('q')||''}).catch(()=>{});
  });
}

document.addEventListener('click',async event=>{
  const button=event.target.closest('[data-copy-coupon]');
  if(!button)return;
  try{await navigator.clipboard.writeText(button.dataset.copyCoupon);button.textContent='Copiado!';setTimeout(()=>button.textContent='Copiar',1600)}catch{button.textContent=button.dataset.copyCoupon}
});

document.addEventListener('click',event=>{
  const button=event.target.closest('[data-clear-viewed]');
  if(!button)return;
  try{localStorage.removeItem(VIEWED_PRODUCTS_KEY)}catch{}
  button.closest('.continue-viewing-section')?.remove();
});

document.addEventListener('click',event=>{
  const card=event.target.closest('[data-card-url]');
  if(!card||event.target.closest('button,a'))return;
  location.href=card.dataset.cardUrl;
});
document.addEventListener('keydown',event=>{
  const card=event.target.closest('[data-card-url]');
  if(!card||event.target!==card||!['Enter',' '].includes(event.key))return;
  event.preventDefault();
  location.href=card.dataset.cardUrl;
});
